import{_ as a,o,c as i,a0 as s}from"./chunks/framework.BjpW4enL.js";const m=JSON.parse('{"title":"ADR-0025: Tipagem Vetorial por Projeção (Vector Typing per Projection)","description":"","frontmatter":{},"headers":[],"relativePath":"20_Arquitetura/adr/0025-vector-typing-per-projection.md","filePath":"20_Arquitetura/adr/0025-vector-typing-per-projection.md","lastUpdated":1782592277000}'),t={name:"20_Arquitetura/adr/0025-vector-typing-per-projection.md"};function r(d,e,n,l,c,p){return o(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="adr-0025-tipagem-vetorial-por-projecao-vector-typing-per-projection" tabindex="-1">ADR-0025: Tipagem Vetorial por Projeção (Vector Typing per Projection) <a class="header-anchor" href="#adr-0025-tipagem-vetorial-por-projecao-vector-typing-per-projection" aria-label="Permalink to &quot;ADR-0025: Tipagem Vetorial por Projeção (Vector Typing per Projection)&quot;">​</a></h1><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>Pensamento — ideias em discussão, nenhuma decisão tomada.</p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>O NEXUS hoje classifica arquivos por <code>file_type</code> (extensão: <code>.rs</code>, <code>.ts</code>, <code>.sql</code>) e armazena todos os vetores L1/L2 no mesmo espaço dimensional (768d, Cosine).</p><p>Issues observadas:</p><ol><li><p><strong>Extensão não é identidade segura</strong> — um <code>.txt</code> pode conter um prompt malicioso ou um executável. Confiar em extensão como classificador é frágil.</p></li><li><p><strong>Distância semântica entre tipos diferentes</strong> — chunks de código Rust e AST JSON não deveriam competir no mesmo ranking de similaridade. Misturá-los cria &quot;atratores&quot; onde documentos estruturalmente diferentes mas estatisticamente próximos poluem o resultado T3.</p></li><li><p><strong>Dimensionalidade única para todo dado</strong> — código, documentação, SQL, reflections e metadados têm complexidades semânticas diferentes. Forçar todos pro mesmo espaço (768d) ou perde nuance (dados complexos) ou desperdiça recursos (dados simples).</p></li><li><p><strong>Coleções fixas no Qdrant</strong> — <code>nexus_ast</code>, <code>nexus_ghost</code>, <code>nexus_reflections</code> são definidas em tempo de deploy. Não há como criar uma coleção sob demanda para uma projeção T4 específica.</p></li></ol><h2 id="drivers-da-decisao" tabindex="-1">Drivers da Decisão <a class="header-anchor" href="#drivers-da-decisao" aria-label="Permalink to &quot;Drivers da Decisão&quot;">​</a></h2><ul><li><strong>Segurança</strong>: não confiar em extensão de arquivo como classificador de tipo</li><li><strong>Precisão semântica</strong>: separar espaços vetoriais por natureza do dado</li><li><strong>Flexibilidade</strong>: permitir que projeções T4 criem coleções Qdrant sob demanda</li><li><strong>Eficiência</strong>: dimensionalidade adequada ao conteúdo, não global</li><li><strong>Extensibilidade</strong>: suporte para tipos de dado não previstos em código (LLM-generated)</li></ul><h2 id="ideias-em-discussao" tabindex="-1">Ideias em Discussão <a class="header-anchor" href="#ideias-em-discussao" aria-label="Permalink to &quot;Ideias em Discussão&quot;">​</a></h2><h3 id="ideia-1-tipo-vetorial-por-projecao-t4" tabindex="-1">Ideia 1: Tipo Vetorial por Projeção T4 <a class="header-anchor" href="#ideia-1-tipo-vetorial-por-projecao-t4" aria-label="Permalink to &quot;Ideia 1: Tipo Vetorial por Projeção T4&quot;">​</a></h3><p>Cada combinação <code>(project, criteria, file_type)</code> no T4 poderia ter seu próprio esquema vetorial. A primeira vez que uma projeção é consultada, uma coleção Qdrant é criada sob demanda com dimensionalidade configurável.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>nexus:part_of:rust          → coleção qdrant &quot;proj_nexus_part_of_rust&quot; (768d)</span></span>
<span class="line"><span>intraclinica:depends_on:ts  → coleção qdrant &quot;proj_intra_dep_ts&quot; (384d)</span></span>
<span class="line"><span>nexus:semantic_bridge:md    → coleção qdrant &quot;proj_nexus_bridge_md&quot; (1536d)</span></span></code></pre></div><p>Vantagens:</p><ul><li>Isolamento total entre espaços semânticos</li><li>Dimensionalidade adequada por tipo</li><li>Sem atratores entre tipos diferentes</li></ul><p>Desvantagens:</p><ul><li>Multiplicidade de coleções (centenas?)</li><li>Custo de criar coleção sob demanda</li><li>Complexidade de roteamento de query</li></ul><h3 id="ideia-2-classificador-llm-no-lugar-de-extensao" tabindex="-1">Ideia 2: Classificador LLM no Lugar de Extensão <a class="header-anchor" href="#ideia-2-classificador-llm-no-lugar-de-extensao" aria-label="Permalink to &quot;Ideia 2: Classificador LLM no Lugar de Extensão&quot;">​</a></h3><p>Em vez de <code>file_type</code> derivado de extensão, usar um LLM leve para classificar o tipo real do conteúdo:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>arquivo &quot;notas.txt&quot; com conteúdo SQL   → type: &quot;sql&quot;</span></span>
<span class="line"><span>arquivo &quot;script.txt&quot; com código Python → type: &quot;python&quot;</span></span>
<span class="line"><span>arquivo &quot;README.md&quot; com prompt injetado → type: &quot;prompt_injection&quot;</span></span></code></pre></div><p>Isso resolve o problema de segurança e dá uma classificação semântica real. O classificador poderia ser o próprio <code>nomic-embed-text</code> ou um modelo pequeno como <code>qwen2.5-coder:1.5b</code>.</p><h3 id="ideia-3-schema-vetorial-definido-por-llm" tabindex="-1">Ideia 3: Schema Vetorial Definido por LLM <a class="header-anchor" href="#ideia-3-schema-vetorial-definido-por-llm" aria-label="Permalink to &quot;Ideia 3: Schema Vetorial Definido por LLM&quot;">​</a></h3><p>Ir além da dimensionalidade fixa: o LLM poderia sugerir o esquema vetorial ótimo para cada tipo de dado:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;documentação técnica longa&quot; → 1536d, Distance=Cosine</span></span>
<span class="line"><span>&quot;código fonte&quot;               → 768d, Distance=Cosine  </span></span>
<span class="line"><span>&quot;reflections (L3)&quot;           → 384d, Distance=Dot</span></span>
<span class="line"><span>&quot;métrica de drift&quot;           → 128d, Distance=Manhattan</span></span></code></pre></div><p>Isso seria uma otimização futura — requer experimentação para validar se dimensionalidade variável melhora recall/precision.</p><h3 id="ideia-4-tabelas-relacionais-por-no-no-postgresql" tabindex="-1">Ideia 4: Tabelas Relacionais por Nó no PostgreSQL <a class="header-anchor" href="#ideia-4-tabelas-relacionais-por-no-no-postgresql" aria-label="Permalink to &quot;Ideia 4: Tabelas Relacionais por Nó no PostgreSQL&quot;">​</a></h3><p>Cada tipo de nó T4 poderia ter sua própria tabela no PostgreSQL em vez de uma <code>abstractions</code> monolítica:</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CREATE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> TABLE</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> nodes_rust</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (id UUID, ...);   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- nós de código Rust</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CREATE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> TABLE</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> nodes_sql</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (id UUID, ...);    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- nós de SQL</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CREATE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> TABLE</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> nodes_doc</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (id UUID, ...);    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- nós de documentação</span></span></code></pre></div><p>Isso permitiria schemas diferentes por tipo de nó e consultas mais eficientes. O <code>abstractions</code> atual continuaria existindo como view unificada (polimórfica).</p><h2 id="questoes-em-aberto" tabindex="-1">Questões em Aberto <a class="header-anchor" href="#questoes-em-aberto" aria-label="Permalink to &quot;Questões em Aberto&quot;">​</a></h2><ul><li>[ ] Vale a pena ter N coleções Qdrant ou uma coleção com filtro de payload basta?</li><li>[ ] O classificador LLM deve ser síncrono (bloqueia ingest) ou async (eventual)?</li><li>[ ] A dimensionalidade variável é suportada pelo reranking no T3?</li><li>[ ] Como migrar dados existentes (L1=218 pts, L2=0, L3=0)?</li><li>[ ] Tabelas separadas no PG vs <code>abstractions</code> com JSONB — qual escala melhor?</li><li>[ ] O <code>file_type</code> atual (derivado de extensão) deve ser mantido como fallback?</li></ul><h2 id="riscos" tabindex="-1">Riscos <a class="header-anchor" href="#riscos" aria-label="Permalink to &quot;Riscos&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Risco</th><th>Severidade</th><th>Mitigação</th></tr></thead><tbody><tr><td>Explosão de coleções Qdrant</td><td>Média</td><td>Usar prefixo de projeção + cleanup de coleções não usadas</td></tr><tr><td>Classificador LLM errar tipo</td><td>Média</td><td>Fallback para extensão + revisão periódica</td></tr><tr><td>Performance com N coleções</td><td>Baixa</td><td>Qdrant escala horizontalmente; coleções são baratas</td></tr><tr><td>Complexidade operacional</td><td>Média</td><td>Automatizar criação/cleanup de coleções via script</td></tr></tbody></table><h2 id="proximos-passos" tabindex="-1">Próximos Passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos Passos&quot;">​</a></h2><ol><li>Consertar pipeline L2 atual (ghost vazio — bug de formato de vetor)</li><li>Validar se coleção única com filtro de payload atende aos mesmos requisitos</li><li>Prototipar classificador LLM leve para <code>file_type</code> semântico</li><li>Decidir se tabelas separadas ou <code>abstractions</code> polimórfica</li></ol><h2 id="referencias" tabindex="-1">Referências <a class="header-anchor" href="#referencias" aria-label="Permalink to &quot;Referências&quot;">​</a></h2><ul><li>ADR-0002: Operadores Relacionais T4 (define o sistema de projeção)</li><li>ADR-0024: Backpropagation Charges (introduz heat como sinal fraco)</li><li><code>docs/T4_GRAPH_NORMS.md</code> (eixos de projeção)</li><li>Issue: Qdrant ghost vazio — named vs unnamed vector mismatch</li></ul>`,37)])])}const h=a(t,[["render",r]]);export{m as __pageData,h as default};
